#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using PVZEngine;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.skeletonStatue_Death)]
    public class SkeletonStatue_Death : EnemyDeathDisappearBehaviour
    {
        public SkeletonStatue_Death(string nsp, string name) : base(nsp, name)
        {
        }
        public override void PostDeath(Entity entity, DeathInfo info)
        {
            if (info.HasEffect(VanillaDamageEffects.DROWN) || info.HasEffect(VanillaDamageEffects.FALL_OFF))
            {
                base.PostDeath(entity, info);
                return;
            }
            if (SkeletonStatue.IsReviving(entity) || entity.WillRemoveOnDeath(info))
            {
                entity.Remove();
            }
            else
            {
                entity.Revive();
                entity.Health = entity.GetMaxHealth();
                SkeletonStatue.SetReviving(entity, true);
                var timer = SkeletonStatue.GetReviveTimer(entity);
                if (timer != null)
                {
                    timer.ResetSeconds(SkeletonStatue.REVIVE_SECONDS);
                }
            }
        }
    }
}
